import type { ComponentType } from 'react';

export type SDUIContextValue =
  | string
  | number
  | boolean
  | null
  | SDUIContext
  | SDUIContextValue[];

export type SDUIContext = {
  [key: string]: SDUIContextValue;
};

// ---- 3.5  JSON Logic (subset) --------------------------------------------

/**
 * Accesses a value from the context using dot notation.
 * @example { var: 'balance.pointsFormatted' }
 */
export type SDUIVarOperator = {
  var: string;
};

export type SDUILogicPrimitive = string | number | boolean | null;
export type SDUILogicOperand =
  | SDUIVarOperator
  | SDUILogicPrimitive
  | SDUIRule
  | SDUIArithmeticExpression;

export type SDUIComparisonRule = {
  '=='?: [SDUILogicOperand, SDUILogicOperand];
  '!='?: [SDUILogicOperand, SDUILogicOperand];
  '>'?: [SDUILogicOperand, SDUILogicOperand];
  '<'?: [SDUILogicOperand, SDUILogicOperand];
  '>='?: [SDUILogicOperand, SDUILogicOperand];
  '<='?: [SDUILogicOperand, SDUILogicOperand];
};

export type SDUILogicalRule = {
  and?: SDUIRule[];
  or?: SDUIRule[];
  '!'?: SDUIRule;
};

export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;

export type SDUIArithmeticExpression = {
  '+'?: SDUIExpressionOperand[];
  '-'?: [SDUIExpressionOperand, SDUIExpressionOperand];
  '*'?: SDUIExpressionOperand[];
  '/'?: [SDUIExpressionOperand, SDUIExpressionOperand];
  min?: SDUIExpressionOperand[];
  max?: SDUIExpressionOperand[];
};

export type SDUIExpressionOperand =
  | SDUIVarOperator
  | SDUILogicPrimitive
  | SDUIArithmeticExpression
  | SDUIRule;

/**
 * A boolean value computed from a JSON Logic rule.
 * Used for visibility, enabled state, or any boolean prop.
 * @example { rule: { '>': [{ var: 'form.points' }, 0] } }
 */
export type SDUIConditional = {
  rule: SDUIRule;
};

export type SDUIValidationRule = {
  rule: SDUIRule;
  message: string;
};

export type SDUIValidation = {
  rules: SDUIValidationRule[];
};


export type SDUITextNode = {
  type: 'text';
  value: string;
  bold?: boolean;
  italic?: boolean;
  color?: string;
};

export type SDUILinkNode = {
  type: 'link';
  text: string;
  to: string;
  trackEvent?: string;
};

export type SDUIIconNode = {
  type: 'icon';
  name: string;
  color?: string;
  size?: number;
};

export type SDUILineBreakNode = {
  type: 'br';
};

export type SDUIRichTextChild =
  | SDUITextNode
  | SDUILinkNode
  | SDUIIconNode
  | SDUILineBreakNode;

export type SDUIRichText = {
  type: 'rich_text';
  children: SDUIRichTextChild[];
};

export type SDUIPropValue =
  | string
  | number
  | boolean
  | null
  | SDUIConditional
  | SDUIValidation
  | SDUIRichText
  | SDUIPropValue[]
  | SDUIComponentProps;

export type SDUIComponentProps = {
  [key: string]: SDUIPropValue | undefined;
};

export type SDUIComponent<T extends string = string> = {
  type: T;
  props: SDUIComponentProps;
  visible?: SDUIConditional;
};

// ---- 3.1  Screen Structure ------------------------------------------------

export type SDUIHeader = SDUIComponent;
export type SDUIFooter = SDUIComponent;

export type SDUIScreen = {
  id: string;
  context: SDUIContext;
  header?: SDUIHeader;
  body: SDUIComponent[];
  footer?: SDUIFooter;
};

export type SDUIScreenResponse = {
  screen: SDUIScreen;
};

// ---- Component Registry ---------------------------------------------------

export type SDUIComponentRenderer<
  P extends SDUIComponentProps = SDUIComponentProps,
> = ComponentType<{
  props: P;
  context: SDUIContext;
  onAction?: (descriptor: SDUIActionDescriptor) => void;
}>;

export type SDUIComponentRegistry = {
  [type: string]: SDUIComponentRenderer;
};

// ---- Known Component Types (voucher screens) ------------------------------

export const SDUI_KNOWN_TYPES = [
  'heading',
  'text',
  'balance_display',
  'points_input',
  'button',
  'link',
  'alert',
  'list_text_icon',
  'separator',
  'icon_text_row',
  'section_heading',
  'nav_header',
  'rich_text',
  'voucher_card',
  'empty_state',
  'points_card',
  'tab_bar',
  'transaction_item',
  'date_separator',
  'detail_header',
  'tag_label',
  'key_value_row',
  'card_activity',
] as const;


export const SDUI_ACTION_TYPES = [
  'navigate',
  'goBack',
  'replace',
  'deepLink',
  'fetch',
  'submit',
  'retry',
  'setValue',
  'setComputed',
  'useAll',
  'open',
  'close',
  'trackScreenView',
  'trackSelect',
  'trackModalView',
  'setState',
  'reset',
  'openURL',
  'phoneCall',
] as const;

export type SDUIActionType = (typeof SDUI_ACTION_TYPES)[number];

export type SDUIActionDescriptor<
  T extends string = string,
  P extends Record<string, unknown> = Record<string, unknown>,
> = {
  type: T;
  payload?: P;
};

export type SDUINavigateAction = SDUIActionDescriptor<
  'navigate',
  {
    screen: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUIGoBackAction = SDUIActionDescriptor<'goBack'>;
export type SDUIReplaceAction = SDUIActionDescriptor<
  'replace',
  {
    screen: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUIDeepLinkAction = SDUIActionDescriptor<
  'deepLink',
  { url: string }
>;

export type SDUIFetchAction = SDUIActionDescriptor<
  'fetch',
  {
    service: string;
    method: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUISubmitAction = SDUIActionDescriptor<
  'submit',
  {
    service: string;
    method: string;
    payload: Record<string, unknown>;
  }
>;
export type SDUIRetryAction = SDUIActionDescriptor<'retry', { refetch: true }>;

export type SDUISetValueAction = SDUIActionDescriptor<
  'setValue',
  {
    contextKey: string;
    value: unknown;
  }
>;
export type SDUISetComputedAction = SDUIActionDescriptor<
  'setComputed',
  {
    contextKey: string;
    formula: SDUIArithmeticExpression;
  }
>;
export type SDUIUseAllAction = SDUIActionDescriptor<
  'useAll',
  {
    sourceKey: string;
    targetKey: string;
  }
>;

export type SDUIOpenModalAction = SDUIActionDescriptor<
  'open',
  { modalId: string }
>;
export type SDUICloseModalAction = SDUIActionDescriptor<
  'close',
  { modalId: string }
>;

export type SDUITrackScreenViewAction = SDUIActionDescriptor<
  'trackScreenView',
  {
    screenName: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUITrackSelectAction = SDUIActionDescriptor<
  'trackSelect',
  {
    contentId: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUITrackModalViewAction = SDUIActionDescriptor<
  'trackModalView',
  { modalName: string }
>;

export type SDUISetStateAction = SDUIActionDescriptor<
  'setState',
  {
    slice: string;
    field: string;
    value: unknown;
  }
>;
export type SDUIResetAction = SDUIActionDescriptor<'reset', { slice: string }>;

export type SDUIOpenURLAction = SDUIActionDescriptor<
  'openURL',
  { url: string }
>;
export type SDUIPhoneCallAction = SDUIActionDescriptor<
  'phoneCall',
  { number: string }
>;

export type SDUIKnownAction =
  | SDUINavigateAction
  | SDUIGoBackAction
  | SDUIReplaceAction
  | SDUIDeepLinkAction
  | SDUIFetchAction
  | SDUISubmitAction
  | SDUIRetryAction
  | SDUISetValueAction
  | SDUISetComputedAction
  | SDUIUseAllAction
  | SDUIOpenModalAction
  | SDUICloseModalAction
  | SDUITrackScreenViewAction
  | SDUITrackSelectAction
  | SDUITrackModalViewAction
  | SDUISetStateAction
  | SDUIResetAction
  | SDUIOpenURLAction
  | SDUIPhoneCallAction;

export type SDUIActionResult = {
  success: boolean;
  error?: string;
  data?: unknown;
};

export type SDUIActionContext = {
  screen: SDUIContext;
  form: Record<string, unknown>;
  setForm: (
    updater: (prev: Record<string, unknown>) => Record<string, unknown>,
  ) => void;
};

export type SDUIActionDeps = {
  navigation?: {
    navigate: (screen: string, params?: Record<string, unknown>) => void;
    goBack: () => void;
    replace: (screen: string, params?: Record<string, unknown>) => void;
  };
  store?: {
    getState: () => Record<string, unknown>;
    setState: (partial: Record<string, unknown>) => void;
  };
  linking?: {
    openURL: (url: string) => void;
  };
  analytics?: {
    eventScreenViewV3: (
      screenName: string,
      params?: Record<string, unknown>,
    ) => void;
    eventSelectContent: (
      contentId: string,
      params?: Record<string, unknown>,
    ) => void;
    eventModalView: (modalName: string) => void;
  };
  signal?: AbortSignal;
};

export type SDUIActionHandler = (
  payload: Record<string, unknown> | undefined,
  actionContext: SDUIActionContext,
  deps: SDUIActionDeps,
) => SDUIActionResult | Promise<SDUIActionResult>;

export type SDUIActionRegistry = Record<string, SDUIActionHandler>;

