    expect(evaluateExpression({ '-': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    expect(evaluateExpression({ '-': [1, 2, 3] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
  });

  it('returns 0 for division with wrong operand count', () => {
    expect(evaluateExpression({ '/': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
  });

