import React from 'react';
import { View, Text as RNText } from 'react-native';
import type { SDUIComponentProps } from '../models';

interface FallbackProps {
  props: SDUIComponentProps;
  type: string;
}

/**
 * Dev-only fallback for unregistered SDUI component types.
 * Uses RN primitives intentionally — DS components require ThemeProvider
 * which may not be available in all rendering contexts (tests, error boundaries).
 */
export default function FallbackComponent({ type, props }: FallbackProps) {
  return (
    <View
      style={{
        padding: 12,
        backgroundColor: '#FFF3CD',
        borderRadius: 8,
        marginBottom: 8,
      }}
    >
      <RNText style={{ fontWeight: 'bold', color: '#856404' }}>
        Unknown component: &quot;{type}&quot;
      </RNText>
      <RNText style={{ color: '#856404', fontSize: 12 }}>
        {JSON.stringify(props, null, 2)}
      </RNText>
    </View>
  );
}

