  'phoneCall',
  { number: string }
>;

export type SDUIKnownAction =
  | SDUINavigateAction
  | SDUIGoBackAction
  | SDUIReplaceAction
  | SDUIDeepLinkAction
  | SDUIFetchAction
  | SDUISubmitAction
  | SDUIRetryAction
  | SDUISetValueAction
  | SDUISetComputedAction
  | SDUIUseAllAction
  | SDUIOpenModalAction
  | SDUICloseModalAction
  | SDUITrackScreenViewAction
  | SDUITrackSelectAction
  | SDUITrackModalViewAction
