export type SDUICloseModalAction = SDUIActionDescriptor<
  'close',
  { modalId: string }
>;

export type SDUITrackScreenViewAction = SDUIActionDescriptor<
  'trackScreenView',
  {
    screenName: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUITrackSelectAction = SDUIActionDescriptor<
  'trackSelect',
  {
    contentId: string;
    params?: Record<string, unknown>;
  }
>;
export type SDUITrackModalViewAction = SDUIActionDescriptor<
  'trackModalView',
  { modalName: string }
>;

export type SDUISetStateAction = SDUIActionDescriptor<
  'setState',
  {
    slice: string;
    field: string;
    value: unknown;
  }
>;
export type SDUIResetAction = SDUIActionDescriptor<'reset', { slice: string }>;

export type SDUIOpenURLAction = SDUIActionDescriptor<
  'openURL',
  { url: string }
>;
export type SDUIPhoneCallAction = SDUIActionDescriptor<
  'phoneCall',
  { number: string }
>;

export type SDUIKnownAction =
  | SDUINavigateAction
  | SDUIGoBackAction
  | SDUIReplaceAction
  | SDUIDeepLinkAction
  | SDUIFetchAction
  | SDUISubmitAction
  | SDUIRetryAction
  | SDUISetValueAction
  | SDUISetComputedAction
  | SDUIUseAllAction
  | SDUIOpenModalAction
  | SDUICloseModalAction
  | SDUITrackScreenViewAction
  | SDUITrackSelectAction
  | SDUITrackModalViewAction
  | SDUISetStateAction
  | SDUIResetAction
  | SDUIOpenURLAction
  | SDUIPhoneCallAction;

export type SDUIActionResult = {
  success: boolean;
  error?: string;
  data?: unknown;
};

export type SDUIActionContext = {
  screen: SDUIContext;
  form: Record<string, unknown>;
  setForm: (
    updater: (prev: Record<string, unknown>) => Record<string, unknown>,
  ) => void;
};

export type SDUIActionDeps = {
  navigation?: {
    navigate: (screen: string, params?: Record<string, unknown>) => void;
    goBack: () => void;
    replace: (screen: string, params?: Record<string, unknown>) => void;
  };
  store?: {
    getState: () => Record<string, unknown>;
    setState: (partial: Record<string, unknown>) => void;
  };
  linking?: {
    openURL: (url: string) => void;
  };
  analytics?: {
    eventScreenViewV3: (
      screenName: string,
      params?: Record<string, unknown>,
    ) => void;
    eventSelectContent: (
      contentId: string,
      params?: Record<string, unknown>,
    ) => void;
    eventModalView: (modalName: string) => void;
  };
  signal?: AbortSignal;
};

export type SDUIActionHandler = (
  payload: Record<string, unknown> | undefined,
  actionContext: SDUIActionContext,
  deps: SDUIActionDeps,
) => SDUIActionResult | Promise<SDUIActionResult>;

export type SDUIActionRegistry = Record<string, SDUIActionHandler>;

import React from 'react';
import { View, Text as RNText } from 'react-native';
import type { SDUIComponentProps } from '../models';

interface FallbackProps {
  props: SDUIComponentProps;
  type: string;
}

/**
 * Dev-only fallback for unregistered SDUI component types.
 * Uses RN primitives intentionally — DS components require ThemeProvider
 * which may not be available in all rendering contexts (tests, error boundaries).
 */
export default function FallbackComponent({ type, props }: FallbackProps) {
  return (
    <View
      style={{
        padding: 12,
        backgroundColor: '#FFF3CD',
        borderRadius: 8,
        marginBottom: 8,
      }}
    >
      <RNText style={{ fontWeight: 'bold', color: '#856404' }}>
        Unknown component: &quot;{type}&quot;
      </RNText>
      <RNText style={{ color: '#856404', fontSize: 12 }}>
        {JSON.stringify(props, null, 2)}
      </RNText>
    </View>
  );
}

import React from 'react';
