} from '../models';

const HeadingAdapter = ({
  props,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => <Text testID="heading">{String(props.text)}</Text>;

const ButtonAdapter = ({
  props,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => <Text testID="button">{String(props.label)}</Text>;

const ActionButtonAdapter = ({
  props,
  onAction,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
  onAction?: (descriptor: SDUIActionDescriptor) => void;
}) => (
  <Pressable
    testID="action-button"
    onPress={() => {
      if (onAction && props.action) {
        onAction(props.action as unknown as SDUIActionDescriptor);
      }
    }}
  >
    <Text>{String(props.label)}</Text>
  </Pressable>
);

const ContextDisplayAdapter = ({
  props,
  context,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => (
  <Text testID="context-display">
    {JSON.stringify(context)}
  </Text>
);

function buildRegistry() {
  let registry = createRegistry();
  registry = registerComponent(registry, 'heading', HeadingAdapter);
  registry = registerComponent(registry, 'button', ButtonAdapter);
  return registry;
}

